    private func makeBars() -> [DailyBar] {
        (0..<closes.count).map { i in
            DailyBar(
                date: String(format: "2024-06-%02d", i + 1),
                open: closes[i],
                close: closes[i],
                high: highs[i],
                low: lows[i],
                volume: 10_000
            )
        }
    }

    /// Element-wise comparison with `NaN`-aware equality: both `NaN` at the
    /// same index passes (mirrors pandas leaving early-window BOLL as NaN);
    /// only one side being `NaN` fails.
    private func assertParity(
        _ actual: [Double],
        _ expected: [Double],
        _ label: String,
        accuracy: Double = 1e-6,
        file: StaticString = #file,
        line: UInt = #line
    ) {
        XCTAssertEqual(actual.count, expected.count, "\(label): count mismatch", file: file, line: line)
        for i in 0..<min(actual.count, expected.count) {
            if expected[i].isNaN {
                XCTAssertTrue(actual[i].isNaN, "\(label)[\(i)]: expected NaN, got \(actual[i])", file: file, line: line)
            } else {
                XCTAssertEqual(actual[i], expected[i], accuracy: accuracy, "\(label)[\(i)]", file: file, line: line)
            }
        }
    }

