    func test_movingAverages_matchPandasMinPeriods1() {
        let mas = TechnicalIndicators.movingAverages(closes: closes)
        assertParity(mas[5] ?? [], expectedMA5, "MA5")
        assertParity(mas[10] ?? [], expectedMA10, "MA10")
        assertParity(mas[20] ?? [], expectedMA20, "MA20")
        assertParity(mas[60] ?? [], expectedMA60, "MA60")
    }

    func test_macd_matchesPandasEwmAdjustFalse() {
        let (dif, dea, macd) = TechnicalIndicators.macd(closes: closes)
        assertParity(dif, expectedDIF, "DIF")
        assertParity(dea, expectedDEA, "DEA")
        assertParity(macd, expectedMACD, "MACD")
