        assertParity(TechnicalIndicators.rsiWilder(closes: closes, period: 24), expectedRSI24, "RSI24")
    }

    /// Regression guard for §0.5-2: the banned simple-average RSI would
    /// produce different numbers than Wilder's EMA on the same data. This
    /// doesn't test a simple-average implementation (there isn't one — it
    /// was never ported), it just confirms Wilder's RSI is *not* accidentally
    /// equal to a naive rolling-mean RSI on this fixture, as a sanity check
    /// that the EMA recursion is actually being used.
    func test_rsiWilder_isNotASimpleRollingMeanRSI() {
        let wilder = TechnicalIndicators.rsiWilder(closes: closes, period: 12)

        // Naive rolling-mean RSI(12), computed independently right here
        // (not shared code with the production implementation) purely to
        // prove the two formulas diverge on this data.
        var gains = [Double](repeating: 0, count: closes.count)
        var losses = [Double](repeating: 0, count: closes.count)
        for i in 1..<closes.count {
            let delta = closes[i] - closes[i - 1]
            gains[i] = delta > 0 ? delta : 0
            losses[i] = delta < 0 ? -delta : 0
        }
        let period = 12
        var naive = [Double](repeating: 50, count: closes.count)
        for i in 0..<closes.count {
            let start = max(0, i - period + 1)
            let avgGain = gains[start...i].reduce(0, +) / Double(i - start + 1)
            let avgLoss = losses[start...i].reduce(0, +) / Double(i - start + 1)
            if avgLoss != 0 {
                naive[i] = 100 - 100 / (1 + avgGain / avgLoss)
            }
        }

        var anyDifferent = false
        for i in 0..<closes.count where abs(wilder[i] - naive[i]) > 1e-6 {
            anyDifferent = true
            break
        }
        XCTAssertTrue(anyDifferent, "Wilder RSI and a naive rolling-mean RSI should diverge on this fixture")
    }

    // MARK: - S6.2 latest signals

    func test_latestSignals_emptyBars_returnsNil() {
        XCTAssertNil(TechnicalIndicators.latestSignals(bars: [], series: TechnicalIndicators.computeAll(bars: [])))
    }

    func test_latestSignals_onFullFixture_matchesHandCheckedExpectations() {
        let bars = makeBars()
        let series = TechnicalIndicators.computeAll(bars: bars)
        guard let signals = TechnicalIndicators.latestSignals(bars: bars, series: series) else {
            return XCTFail("expected non-nil signals for non-empty bars")
        }

        // Cross-checked directly against the reference arrays above at the
        // last index (29) and second-to-last (28):
        // DIF[29]=0.3376 > DEA[29]=0.3015 and DIF[28]=0.3220 > DEA[28]=0.2925 -> no golden cross (already above)
        XCTAssertFalse(signals.macdGoldenCross)
        XCTAssertFalse(signals.macdDeadCross)
        XCTAssertTrue(signals.macdHistogramPositive, "MACD[29]=0.0722 > 0")

        // K[29]=85.21 > D[29]=83.28, K[28]=84.06 > D[28]=82.31 -> already above, no fresh cross
        XCTAssertFalse(signals.kdjGoldenCross)
        XCTAssertFalse(signals.kdjDeadCross)
        XCTAssertTrue(signals.kdjOverbought, "K[29]=85.2 > 80 and D[29]=83.3 > 80")
        XCTAssertFalse(signals.kdjOversold)

        XCTAssertTrue(signals.rsi6Overbought, "RSI6[29]=84.04 > 80")
        XCTAssertFalse(signals.rsi6Oversold)
        XCTAssertTrue(signals.rsi12Overbought, "RSI12[29]=80.86 > 70")
        XCTAssertFalse(signals.rsi12Oversold)

        XCTAssertFalse(signals.priceAboveUpper, "close[29]=11.90 < BOLL_UPPER[29]=11.905")
        XCTAssertFalse(signals.priceBelowLower)
        XCTAssertFalse(signals.bollSqueeze)

        XCTAssertTrue(signals.ma5AboveMa20, "MA5[29]=11.68 > MA20[29]=11.255")
        XCTAssertTrue(signals.ma10AboveMa20, "MA10[29]=11.525 > MA20[29]=11.255")
        XCTAssertTrue(signals.priceAboveMa60, "close[29]=11.90 > MA60[29]=10.977")
    }

    /// Explicitly exercises every boolean's true AND false branch (task.md
    /// S6.2's verification point), using small hand-built series rather than
    /// the big fixture so each case is obvious and isolated.
    func test_latestSignals_everyBranch_trueAndFalse() {
        func series(dif: [Double], dea: [Double], macd: [Double], k: [Double], d: [Double],
                    rsi6: [Double], rsi12: [Double], upper: [Double], mid: [Double], lower: [Double],
                    ma5: [Double], ma20: [Double], ma60: [Double]) -> TechnicalIndicators.Series {
            TechnicalIndicators.Series(
                ma5: ma5, ma10: ma5, ma20: ma20, ma60: ma60,
                dif: dif, dea: dea, macd: macd,
                k: k, d: d, j: Array(repeating: 0, count: dif.count),
                rsi6: rsi6, rsi12: rsi12, rsi24: rsi6,
                bollUpper: upper, bollMid: mid, bollLower: lower
            )
        }
        let bars = [
            DailyBar(date: "d0", open: 10, close: 10, high: 10, low: 10, volume: 1),
            DailyBar(date: "d1", open: 10, close: 10, high: 10, low: 10, volume: 1),
        ]

        // --- MACD golden/dead cross: true branch ---
        var s = series(
            dif: [-0.1, 0.1], dea: [0.0, 0.0], macd: [-0.2, 0.2],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        var signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.macdGoldenCross)
        XCTAssertTrue(signals.macdHistogramPositive)
        XCTAssertFalse(signals.macdDeadCross)

        // --- MACD dead cross: true branch ---
        s = series(
            dif: [0.1, -0.1], dea: [0.0, 0.0], macd: [0.2, -0.2],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.macdDeadCross)
        XCTAssertFalse(signals.macdHistogramPositive)
        XCTAssertFalse(signals.macdGoldenCross)

        // --- KDJ golden/dead cross + overbought/oversold ---
        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [40, 85], d: [45, 82], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.kdjGoldenCross)
        XCTAssertTrue(signals.kdjOverbought)
        XCTAssertFalse(signals.kdjDeadCross)
        XCTAssertFalse(signals.kdjOversold)

        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [85, 15], d: [82, 18], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.kdjDeadCross)
        XCTAssertTrue(signals.kdjOversold)
        XCTAssertFalse(signals.kdjGoldenCross)
        XCTAssertFalse(signals.kdjOverbought)

        // --- RSI overbought/oversold thresholds (6 uses 80/20, 12 uses 70/30) ---
        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 85], rsi12: [50, 75],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.rsi6Overbought)
        XCTAssertTrue(signals.rsi12Overbought)
        XCTAssertFalse(signals.rsi6Oversold)
        XCTAssertFalse(signals.rsi12Oversold)

        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 15], rsi12: [50, 25],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.rsi6Oversold)
        XCTAssertTrue(signals.rsi12Oversold)
        XCTAssertFalse(signals.rsi6Overbought)
        XCTAssertFalse(signals.rsi12Overbought)

        // --- BOLL breakout + squeeze ---
        let barsAbove = [
            DailyBar(date: "d0", open: 10, close: 10, high: 10, low: 10, volume: 1),
            DailyBar(date: "d1", open: 20, close: 20, high: 20, low: 20, volume: 1),
        ]
        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 15], mid: [10, 10], lower: [0, 5], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: barsAbove, series: s)!
        XCTAssertTrue(signals.priceAboveUpper, "close 20 > upper 15")
        XCTAssertFalse(signals.priceBelowLower)

        let barsBelow = [
            DailyBar(date: "d0", open: 10, close: 10, high: 10, low: 10, volume: 1),
            DailyBar(date: "d1", open: 2, close: 2, high: 2, low: 2, volume: 1),
        ]
        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 15], mid: [10, 10], lower: [0, 5], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: barsBelow, series: s)!
        XCTAssertTrue(signals.priceBelowLower, "close 2 < lower 5")
        XCTAssertFalse(signals.priceAboveUpper)

        // squeeze: (upper-lower)/mid < 0.1
        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 10.4], mid: [10, 10], lower: [0, 9.7], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.bollSqueeze, "(10.4-9.7)/10 = 0.07 < 0.1")

        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 12], mid: [10, 10], lower: [0, 8], ma5: [10, 10], ma20: [10, 10], ma60: [10, 10]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertFalse(signals.bollSqueeze, "(12-8)/10 = 0.4, not < 0.1")

        // --- MA crosses ---
        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 12], ma20: [10, 10], ma60: [10, 8]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertTrue(signals.ma5AboveMa20, "12 > 10")
        XCTAssertTrue(signals.priceAboveMa60, "close 10 > MA60 8")

        s = series(
            dif: [0, 0], dea: [0, 0], macd: [0, 0],
            k: [50, 50], d: [50, 50], rsi6: [50, 50], rsi12: [50, 50],
            upper: [100, 100], mid: [10, 10], lower: [0, 0], ma5: [10, 8], ma20: [10, 10], ma60: [10, 15]
        )
        signals = TechnicalIndicators.latestSignals(bars: bars, series: s)!
        XCTAssertFalse(signals.ma5AboveMa20, "8 not > 10")
        XCTAssertFalse(signals.priceAboveMa60, "close 10 not > MA60 15")
    }

    func test_latestSignals_singleBar_crossSignalsAreFalse() {
        // len(df) == 1 -> prev == latest in Python too, so a cross can never
        // be detected (can't be both `>` and `<=` against itself).
        let bars = [DailyBar(date: "d0", open: 10, close: 10, high: 10.5, low: 9.5, volume: 100)]
        let series = TechnicalIndicators.computeAll(bars: bars)
        let signals = TechnicalIndicators.latestSignals(bars: bars, series: series)!

        XCTAssertFalse(signals.macdGoldenCross)
        XCTAssertFalse(signals.macdDeadCross)
        XCTAssertFalse(signals.kdjGoldenCross)
        XCTAssertFalse(signals.kdjDeadCross)
    }
}
